from anthropic import Anthropic
from mytools.registry import ToolRegistry

client = Anthropic()

# Tool groups defined by tag
TOOL_GROUPS = {
    "triage":     ["read", "kb"],
    "billing":    ["billing"],
    "shipping":   ["shipping"],
    "escalation": ["escalation"],
    "account":    ["account", "read"],
}

def select_tools(registry: ToolRegistry, intent: str) -> list[dict]:
    tags = TOOL_GROUPS.get(intent, ["read"])  # default: read-only tools
    tools: list = []
    seen: set[str] = set()
    for tag in tags:
        for t in registry.filter_by_tags(tag):
            if t.name not in seen:
                tools.append(t.to_api_schema())
                seen.add(t.name)
    return tools

def detect_intent(assistant_text: str) -> str:
    """Cheap keyword-based intent detection on the assistant's last reply."""
    text = assistant_text.lower()
    if any(w in text for w in ("invoice", "refund", "payment", "charge", "credit")):
        return "billing"
    if any(w in text for w in ("shipment", "tracking", "delivery", "carrier")):
        return "shipping"
    if any(w in text for w in ("escalate", "supervisor", "ticket", "complaint")):
        return "escalation"
    if any(w in text for w in ("account", "subscription", "plan", "upgrade")):
        return "account"
    return "triage"

import json
from typing import Any

def run_support_agent(
    registry: ToolRegistry,
    user_message: str,
) -> str:
    messages: list[dict[str, Any]] = [{"role": "user", "content": user_message}]
    intent = "triage"  # start with triage tools

    while True:
        active_tools = select_tools(registry, intent)

        resp = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=4096,
            tools=active_tools,
            messages=messages,
        )

        if resp.stop_reason == "end_turn":
            # Extract final text
            for block in resp.content:
                if hasattr(block, "text"):
                    return block.text
            return ""

        if resp.stop_reason != "tool_use":
            break

        messages.append({"role": "assistant", "content": resp.content})

        # Detect intent shift from any text blocks in the response
        for block in resp.content:
            if hasattr(block, "text") and block.text:
                intent = detect_intent(block.text)
                break

        # Dispatch tool calls
        tool_results = []
        for block in resp.content:
            if block.type != "tool_use":
                continue
            tool_def = registry.get(block.name)
            if tool_def is None:
                result: dict = {"error": "NOT_FOUND",
                                "message": f"Tool '{block.name}' not available"}
            else:
                result = tool_def.handler(**block.input)
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": json.dumps(result),
            })
        messages.append({"role": "user", "content": tool_results})

    return ""

_ALWAYS_ON = ["clarify_request", "escalate_to_human", "end_conversation"]

def select_tools_with_baseline(
    registry: ToolRegistry,
    intent: str,
) -> list[dict]:
    selected = select_tools(registry, intent)
    seen = {t["name"] for t in selected}
    for name in _ALWAYS_ON:
        tool_def = registry.get(name)
        if tool_def and name not in seen:
            selected.append(tool_def.to_api_schema())
    return selected

def dispatch_tool_call(
    registry,
    name: str,
    inputs: dict,
    allowed_names: set[str],
) -> dict:
    """
    Dispatch a tool call. Returns an error dict if the tool is not in
    the allowed set or not found in the registry.
    """
    if name not in allowed_names:
        # Log this — it indicates an intent classification mismatch
        _LOG.warning("model called tool '%s' not in active set %s", name, allowed_names)
        return {
            "error": "NOT_FOUND",
            "message": (
                f"Tool '{name}' is not available in the current context. "
                "Try describing what you need and I will use an available tool."
            ),
        }
    tool_def = registry.get(name)
    if tool_def is None:
        return {"error": "NOT_FOUND", "message": f"Tool '{name}' is not registered"}
    return tool_def.handler(**inputs)
